boot.artifact:
// inferred-not-tested:artifact 列 H0 探针未闭合前按此推断写
import { html as renderDiff } from 'https://cdn.jsdelivr.net/npm/diff2html@3/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/diff2html@3/bundles/css/diff2html.min.css'; document.head.append(css);
const el = document.getElementById('diff'); el.style.cssText = 'height:480px;overflow:auto';
el.innerHTML = renderDiff(data.diff, { outputFormat: data.outputFormat ?? 'side-by-side', drawFileList: data.drawFileList ?? true, matching: data.matching ?? 'lines', diffStyle: data.diffStyle ?? 'word' });

